    "wizard_region_input": "Shigar naka state ko region don localized mizani (e.g., 'California').",
    "wizard_search_btn": "Bincika don mizani daidaitawa naka query da matakin aji.",
    "wizard_search_result_link": "Danna zuwa duba full mizani description da requirements.",
    "wizard_search_result_select": "Zaɓi wannan mizani zuwa haɗ it naka abun ciki alignment.",
    "wizard_skip_btn": "Tsallaka setup mai jagora da go directly zuwa main interface tare da tsohuwa saiti.",
    "wizard_standard_select": "Zaɓi mizani framework (Common Core, NGSS, state-na musamman) don alignment.",
    "wizard_std_manual_add_btn": "Manually ƙara mizani code wancan wasn't found bincika.",
    "wizard_std_manual_input": "Shigar mizani code manually (e.g., 'CCSS.ELA-LITERACY.RI.5.1').",
    "wizard_std_mode_ai": "Yi amfani AI zuwa automatically identify relevant mizani daga naka abun ciki.",
